/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCL2200000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.initSearch();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("strtDt", utilLib.getCurrentDate("yyyy"));
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

/**
 * 화면 초기화 후 data를 조회한다.
 * @param
 * @return
 */
scwin.initSearch = function() {
	var strtDate = dmaSearchParam.get("strtDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = radSNs.getValue();
	var ecsElcpwstnDivCd = dmaSearchParam.get("elcpwstnCd");

	if (String(strtDate).length != 4) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	}

	var queryStringSnpw = `?strtDt=${strtDate}`;
	queryStringSnpw += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryStringSnpw += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryStringSnpw += `&ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;

	// 태양광
	var optionSnpw = {
		action : "cl/recexcclc/retrieve-rec-excclc.do"
			+ queryStringSnpw,
		method : "get",
		resData : dltRecExcclcSnpwList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, optionSnpw);

	var queryStringNotSnpw = `?strtDt=${strtDate}`;
	queryStringNotSnpw += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryStringNotSnpw += `&ecsSetcscDivCd=02`;
	queryStringNotSnpw += `&ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;

	// 비태양광
	var optionNotSnpw = {
		action : "cl/recexcclc/retrieve-rec-excclc.do"
			+ queryStringNotSnpw,
		method : "get",
		resData : dltRecExcclcNotSnpwList,
		success : "scwin.inqireCallbackNotSnpw",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, optionNotSnpw);
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var strtDate = dmaSearchParam.get("strtDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = radSNs.getValue();
	var ecsElcpwstnDivCd = dmaSearchParam.get("elcpwstnCd");

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;

	if (ecsSetcscDivCd == "01") {
		// 태양광
		var option = {
			action : "cl/recexcclc/retrieve-rec-excclc.do"
				+ queryString,
			method : "get",
			resData : dltRecExcclcSnpwList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
	} else {
		// 비태양광
		var option = {
			action : "cl/recexcclc/retrieve-rec-excclc.do"
				+ queryString,
			method : "get",
			resData : dltRecExcclcNotSnpwList,
			success : "scwin.inqireCallbackNotSnpw",
			isShowMeg : false
		};
	}
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	spnTotalRowSnpw.setValue(dltRecExcclcSnpwList.getRowCount());
	var mandatoryList = scwin.initData.valInfoSnpw.filter(obj => obj.mandatory);

	for (var i = 0; i < dltRecExcclcSnpwList.getRowCount(); i++) {
		mandatoryList.forEach(obj => {
			grdRecExcclcSnpwList.setCellReadOnly(i, obj.id, true);
		});
	}
	scwin.initData.isValidateSnpw = false;
};

/**
 * 비태양광 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallbackNotSnpw = function() {
	spnTotalRowNotSnpw.setValue(dltRecExcclcNotSnpwList.getRowCount());
	var mandatoryList = scwin.initData.valInfoNotSnpw.filter(obj => obj.mandatory);

	for (var i = 0; i < dltRecExcclcNotSnpwList.getRowCount(); i++) {
		mandatoryList.forEach(obj => {
			grdRecExcclcNotSnpwList.setCellReadOnly(i, obj.id, true);
		});
	}
	scwin.initData.isValidateNotSnpw = false;
};

/**
 * 태양광 그리드뷰 행을 추가한다.
 * @param
 * @return
 */
scwin.btnAddRow1_onclick = function() {
	var newIndex = dltRecExcclcSnpwList.insertRow();

	grdRecExcclcSnpwList.setFocusedCell(newIndex, "elcpwstnNm", true);
};

/**
 * 태양광 그리드뷰 행을 삭제한다.
 * @param
 * @return
 */
scwin.btnDelRow1_onclick = function() {
	var rowIndexsList = grdRecExcclcSnpwList.getAllFocusedRowIndex();

	dltRecExcclcSnpwList.removeRows(rowIndexsList);
};

/**
 * 비태양광 그리드뷰 행을 추가한다.
 * @param
 * @return
 */
scwin.btnAddRow2_onclick = function() {
	var newIndex = dltRecExcclcNotSnpwList.insertRow();

	grdRecExcclcNotSnpwList.setFocusedCell(newIndex, "elcpwstnNm", true);
};

/**
 * 비태양광 그리드뷰 행을 삭제한다.
 * @param
 * @return
 */
scwin.btnDelRow2_onclick = function() {
