	dltRecExcclcNotSnpwList.removeRows(rowIndexsList);
};

/**
 * 그리드뷰의 내용을 검증한다.
 * @param
 * @return
 */
scwin.btnValidate_onclick = function(confirmValue) {
	if (confirmValue == true || confirmValue == undefined) {
		var ecsSetcscDivCd = radSNs.getValue();

		if (ecsSetcscDivCd == "01") {
			if (dltRecExcclcSnpwList.getModifiedData() == "") {
				// 처리할 데이터가 없습니다.
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
				return;
			} else if (dltRecExcclcSnpwList.getModifiedJSON().length) {
				var isAllNull = true;
				dltRecExcclcSnpwList.getModifiedJSON().forEach(obj => {
					Object.keys(obj).forEach(key => {
						if (isAllNull) {
							if (key.startsWith("mon")) {
								isAllNull = obj[key] && obj[key] != "" ? false : true;
							}
						} else {
							return;
						}
					});
					if (!isAllNull) {
						return;
					}
				});
				if (isAllNull) {
					comLib.alert($p, "월 항목중 하나 이상의 데이터를 넣어야됩니다.");
					return;
				}
			}

			if (utilLib.validateGridView(grdRecExcclcSnpwList, scwin.initData.valInfoSnpw)) {
				var columnList = scwin.initData.valInfoSnpw.filter(obj => obj.mandatory); //.flatMap(obj => obj.id.replace("elcpwstnNm", "recEqpCdNm"));
				if (ecsLib.gridViewPkDuplicationCheck(grdRecExcclcSnpwList, dltRecExcclcSnpwList, columnList)) {
					// 중복 데이터가 있습니다.
					return;
				}

				if (ecsLib.validateGridViewAcb(grdRecExcclcSnpwList, dltAutoCondition3, scwin.initData.acbMappingCdObjSnpw, scwin.initData.acbMappingNmObjSnpw)) {
					// 해당하는 {컬럼명}이(가) 존재하지 않습니다.
					return;
				}
				scwin.initData.isValidateSnpw = true;
				if (scwin.initData.isSaveProcess) {
					scwin.initData.isSaveProcess = false;
					scwin.btnSave_onclick();
				} else {
					// 데이터 검증이 완료되었습니다.
					comLib.alert($p, utilLib.getMessage("ECS.INFO.00102"));
				}
			}
		} else {
			if (dltRecExcclcNotSnpwList.getModifiedData() == "") {
				// 처리할 데이터가 없습니다.
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
				return;
			} else if (dltRecExcclcNotSnpwList.getModifiedJSON().length) {
				var isAllNull = true;
				dltRecExcclcNotSnpwList.getModifiedJSON().forEach(obj => {
					Object.keys(obj).forEach(key => {
						if (isAllNull) {
							if (key.startsWith("mon")) {
								isAllNull = obj[key] && obj[key] != "" ? false : true;
							}
						} else {
							return;
						}
					});
					if (!isAllNull) {
						return;
					}
				});
				if (isAllNull) {
					comLib.alert($p, "월 항목중 하나 이상의 데이터를 넣어야됩니다.");
					return;
				}
			}

			if (utilLib.validateGridView(grdRecExcclcNotSnpwList, scwin.initData.valInfoNotSnpw)) {
				var columnList = scwin.initData.valInfoNotSnpw.filter(obj => obj.mandatory);
				if (ecsLib.gridViewPkDuplicationCheck(grdRecExcclcNotSnpwList, dltRecExcclcNotSnpwList, columnList)) {
					// 중복 데이터가 있습니다.
					return;
				}

				if (ecsLib.validateGridViewAcb(grdRecExcclcNotSnpwList, dltAutoCondition4, scwin.initData.acbMappingCdObjNotSnpw, scwin.initData.acbMappingNmObjNotSnpw)) {
					// 해당하는 {컬럼명}이(가) 존재하지 않습니다.
					return;
				}
				scwin.initData.isValidateNotSnpw = true;
				if (scwin.initData.isSaveProcess) {
					scwin.initData.isSaveProcess = false;
					scwin.btnSave_onclick();
				} else {
					// 데이터 검증이 완료되었습니다.
					comLib.alert($p, utilLib.getMessage("ECS.INFO.00102"));
				}
			}
		}
	} else {
		scwin.initData.isSaveProcess = false;
	}
};

/**
 * 그리드뷰의 내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	scwin.initData.isSaveProcess = false;
	var ecsSetcscDivCd = radSNs.getValue();

	if (ecsSetcscDivCd == "01") {
		// 태양광
		if (dltRecExcclcSnpwList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}
		if (scwin.initData.isValidateSnpw) {
			var addCount = 0;
			var modifyCount = 0;
			var delCount = 0;
			dltRecExcclcSnpwList.getModifiedJSON().forEach(obj => {
				var rowStatus = obj.rowStatus;
				switch(rowStatus) {
					case "C":
						// 추가
						addCount++;
						break;
					case "U":
						// 수정
						modifyCount++;
						break;
					case "E":
						// 삭제
						delCount++;
						break;
					default:
						break;
				}
			});
			var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
			// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
			ecsLib.saveRsn($p, `${dltRecExcclcSnpwList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
		} else {
			scwin.initData.isSaveProcess = true;
			// 데이터 검증 후 저장 가능합니다.\n검증하시겠습니까?
			comLib.confirm($p, utilLib.getMessage("ECS.INFO.00101"), "scwin.btnValidate_onclick", true);
			return;
		}
	} else {
		// 비태양광
		if (dltRecExcclcNotSnpwList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}
		if (scwin.initData.isValidateNotSnpw) {
			var addCount = 0;
			var modifyCount = 0;
			var delCount = 0;
			dltRecExcclcNotSnpwList.getModifiedJSON().forEach(obj => {
				var rowStatus = obj.rowStatus;
				switch(rowStatus) {
					case "C":
						// 추가
						addCount++;
						break;
					case "U":
						// 수정
						modifyCount++;
						break;
					case "E":
						// 삭제
						delCount++;
						break;
					default:
						break;
				}
			});
			var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
			// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
			ecsLib.saveRsn($p, `${dltRecExcclcNotSnpwList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
		} else {
			scwin.initData.isSaveProcess = true;
			// 데이터 검증 후 저장 가능합니다.\n검증하시겠습니까?
			comLib.confirm($p, utilLib.getMessage("ECS.INFO.00101"), "scwin.btnValidate_onclick", true);
			return;
		}
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var ecsSetcscDivCd = radSNs.getValue();
	var requestData = {};
	var queryString = `?ecsSetcscDivCd=${ecsSetcscDivCd}`;

	if (ecsSetcscDivCd == "01") {
		// 태양광
		requestData.dltRecExcclcSnpwList = dltRecExcclcSnpwList.getModifiedJSON();
	} else {
		// 비태양광
		requestData.dltRecExcclcNotSnpwList = dltRecExcclcNotSnpwList.getModifiedJSON();
	}
	var option = {
		action : "cl/recexcclc/process-rec-excclc.do"
			+ queryString,
		reqData : requestData,
		success : "scwin.saveConfirmSuccessCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveConfirmSuccessCallback = function(resBody) {
	comLib.alert($p, resBody.message.code_name);

	scwin.btnInqire_onclick();
};

