/**
 * 화면목록에서 선택한 버튼권한을 삭제한다.
 * @param
 * @return
 */
scwin.btnDel_onclick = function() {
	if (dltRecExcclcSnpwList.getModifiedData() != "") {
		comLib.removeGridView(grdRecExcclcSnpwList);

		// 삭제하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.saveConfirmCallback");
	} else if (dltRecExcclcNotSnpwList.getModifiedData() != "") {
		comLib.removeGridView(grdRecExcclcNotSnpwList);

		// 삭제하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.saveConfirmCallback");
	} else {
		// 삭제할 자료를 선택한 후 처리하시기 바랍니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00252"));
	}
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param
 * @return
 */
scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);
	var ecsSetcscDivCd = radSNs.getValue();

	var queryString = `?ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-rec-cnd-setcsc.do"
			+ queryString,
		method : "get",
		success : "",
		isShowMeg : false
	};

	if (ecsSetcscDivCd == "01") {
		// 태양광
		option.resData = dltAutoCondition3;
	} else {
		// 비태양광
		option.resData = dltAutoCondition4;
	}
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

/**
 * 발전원  라디오버튼 선택에 따라 그리드 화면이 바뀐다.
 * @param
 * @return
 */
scwin.radSNs_onchange = function() {
	var rad = radSNs.getValue();
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = rad;
	var queryString = `?ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;

	var option = {
		action : "zz/cmmn/retrieve-rec-cnd-setcsc.do"
			+ queryString,
		method : "get",
		success : "",
		isShowMeg : false
	};

	if (rad == "01") {
		// 태양광
		option.resData = dltAutoCondition3;
		grpGridSnpw.setStyle("display", "block");
		grpGridNotSnpw.setStyle("display", "none");
		acbCndElcpwstn.setNodeSet("data:" + dltAutoCondition3.getID(), "cmmnCdNm", "cmmnCd");
	} else if (rad == "02") {
		// 비태양광
		option.resData = dltAutoCondition4;
		grpGridSnpw.setStyle("display", "none");
		grpGridNotSnpw.setStyle("display", "block");
		acbCndElcpwstn.setNodeSet("data:" + dltAutoCondition4.getID(), "cmmnCdNm", "cmmnCd");
	}
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("elcpwstnCd", "ALL");
}

scwin.acbElcpwstn_onviewchange = function(info) {
	dmaSearchParam.set("elcpwstnCd", info.newValue);
};

scwin.grdRecExcclcSnpwList_onafteredit = function(row,col,value) {
