/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm1 = spnSnpwTitle.getValue();
	var subTitleNm2 = spnNotSnpwTitle.getValue();
	var ecsSetcscDivCd = radSNs.getValue();

	if (ecsSetcscDivCd == "01") {
		// 엑셀 내부 타이틀 추가_240105
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 76,
			text 		: `${menuNm}_` + `${subTitleNm1}.xlsx`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);
		// 태양광
		options = {
			fileName : `${menuNm}_` + `${subTitleNm1}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			startRowIndex : 1,
			startColumnIndex : 0,
			useDataFormat: true,
			applyDataFormat : true,
			rowHeight : 40,
			useStyle: true,
			hidden: 1
		}
		grdRecExcclcSnpwList.advancedExcelDownload(options, infoArr);
	} else {
		// 엑셀 내부 타이틀 추가_240105
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 40,
			text 		: `${menuNm}_` + `${subTitleNm2}.xlsx`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);
		// 비태양광
		options = {
			fileName : `${menuNm}_` + `${subTitleNm2}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			startRowIndex : 1,
			startColumnIndex : 0,
			useDataFormat: true,
			applyDataFormat : true,
			rowHeight : 40,
			useStyle: true,
			hidden: 1
		}
		grdRecExcclcNotSnpwList.advancedExcelDownload(options, infoArr);
	}
};

