/**
 * 엑셀 내용을 그리드에 저장한다.
 * @return
 */
scwin.grdDrspExcclcList_onfilereadend = function(value) {
	var ecsSetcscDivCd = radSNs.getValue();

	if (ecsSetcscDivCd == "01") {
		// 태양광
		var dltData = dltRecExcclcSnpwList.getAllJSON();
		var dltAuto3 = dltAutoCondition3.getAllJSON();
		// set JSON
		for (var idx = 0; idx < dltData.length; idx++) {
			var elcpwstnNm = (dltAuto3.find(obj => obj.cmmnCd == dltData[idx].elcpwstnNm) || 0).cmmnCd;
			dltRecExcclcSnpwList.setCellData(idx, "elcpwstnNm", elcpwstnNm);
			// 엑셀에서 빈값으로 넣을경우 0으로 나오는 걸 ""으로 수정_231207
			for (var key in dltData) {
				var innerObj = dltData[key];
				for (var innerKey in innerObj) {
					if (innerKey.startsWith("mon") && innerObj[innerKey] === "0") {
						dltData[key][innerKey] = "";
					} else if (innerKey.startsWith("totqy") && innerObj[innerKey] === "0") {
						dltData[key][innerKey] = "";
					}
				}
			}
		}
		// ""로 수정한 거 dlt에 적용하기 
		dltRecExcclcSnpwList.setJSON(dltData);
		// rowStatus 상태값 변경_231208
		for (var idx = 0; idx < dltData.length; idx++) {
			dltRecExcclcSnpwList.modifyRowStatus(idx, "C");
		}
	} else {
		// 비태양광
		var dltData = dltRecExcclcNotSnpwList.getAllJSON();
		var dltAuto4 = dltAutoCondition4.getAllJSON();
		// set JSON
		for (var idx = 0; idx < dltData.length; idx++) {
			var elcpwstnNm = (dltAuto4.find(obj => obj.cmmnCd == dltData[idx].elcpwstnNm) || 0).cmmnCd;
			dltRecExcclcSnpwList.setCellData(idx, "elcpwstnNm", elcpwstnNm);
			// 엑셀에서 빈값으로 넣을경우 0으로 나오는 걸 ""으로 수정_231207
			for (var key in dltData) {
				var innerObj = dltData[key];
				for (var innerKey in innerObj) {
					if (innerKey.startsWith("mon") && innerObj[innerKey] === "0") {
						dltData[key][innerKey] = "";
					} else if (innerKey.startsWith("totqy") && innerObj[innerKey] === "0") {
						dltData[key][innerKey] = "";
					}
				}
			}
		}
		// ""로 수정한 거 dlt에 적용하기 
		dltRecExcclcNotSnpwList.setJSON(dltData);
		// rowStatus 상태값 변경_231208
		for (var idx = 0; idx < dltData.length; idx++) {
			dltRecExcclcNotSnpwList.modifyRowStatus(idx, "C");
		}
	}
};
